const uid = String($node['GET /get-user-profile'].json.query?.uid || '').trim();
const rows = $input.all().map(item => item.json);
const row = rows.find(item => String(item.LINE_UID || '').trim() === uid);
if (!row) return [{ json: { uid, displayName: '', addresses: [] } }];
const addresses = [1,2,3,4,5].map(num => ({
  id: 'addr-' + num,
  label: row['Address_Label_' + num] || row.Branch_Name || ('เธ—เธตเนเธญเธขเธนเน ' + num),
  text: row['Address_' + num] || '',
  contactName: row['Contact_Name_' + num] || row.Contact_Name || row.Display_Name || '',
  tel: row.Tel || '',
})).filter(item => item.text);
return [{ json: { uid, displayName: row.Display_Name || row.Branch_Name || '', branchName: row.Branch_Name || '', isBranch: Boolean(row.Branch_Name), addresses } }];

function parseJson(v,f){try{return v?JSON.parse(v):f}catch{return f}}
const orderId=String($node['GET /get-order'].json.query?.orderId||'').trim();
const row=$input.all().map(i=>i.json).find(r=>String(r.Order_ID||'').trim()===orderId);
if(!row)return[{json:{success:false,message:'Order not found',orderId}}];
const deliveryAddress=parseJson(row.Delivery_Address,{}),details=parseJson(row.Order_Details,{});
return[{json:{orderId:row.Order_ID,timestamp:row.Timestamp,status:row.Status||'Pending',branchInfo:{uid:row.LINE_UID||'',displayName:details.displayName||row.LINE_UID||''},deliveryAddress,orderItems:details.orderItems||[],subtotal:Number(row.Subtotal||0),shippingCost:Number(row.Shipping_Cost||0),discount:Number(row.Discount||0),otherFee:Number(row.Other_Fee||0),vatAmount:Number(row.VAT_Amount||0),totalAmount:Number(row.Total_Amount||0),note:details.note||'',adjustmentReason:row.Adjustment_Reason||'',approvalHistory:parseJson(row.Approval_History,[]),approvedBy:row.Approved_By||'',approvedAt:row.Approved_At||''}}];

function normalizeStatus(status) { return String(status || '').trim().toLowerCase(); }
function isHiddenStatus(status) { return ['ยกเลิก','cancelled','canceled','inactive','disabled','ปิด'].includes(normalizeStatus(status)); }
const query = $node['GET /get-products'].json.query || {};
const customerType = String(query.customerType || 'branch').toLowerCase();
const rows = $input.all().map(item => item.json);
const products = rows.map((row, index) => {
  const productId = row.Product_ID || row.productId || row.ID || row.id || ('P' + String(index + 1).padStart(3, '0'));
  const productName = row.Product_Name || row.productName || row.Name || row.name || '';
  const price = Number(row.Price || row.price || 0);
  const unit = row.Unit || row.unit || '';
  const imageUrl = row.Image_URL || row.imageUrl || row.Image || row.image || '';
  const status = row.Status || row.status || '';
  const audience = String(row.Customer_Type || row.customerType || row.Audience || 'all').trim().toLowerCase();
  const branchOnly = ['branch','สาขา','branch-only','branch_only'].includes(audience);
  return { productId, productName, price, unit, imageUrl, status, customerType: audience };
}).filter(product => product.productName && product.price > 0 && !isHiddenStatus(product.status) && (customerType === 'branch' || product.customerType === 'all' || product.customerType === 'general' || product.customerType === 'ทั่วไป'));
return [{ json: { success: true, customerType, products } }];

function parseJson(value, fallback) { try { return value ? JSON.parse(value) : fallback; } catch { return fallback; } }
const uid = String($node['GET /get-order-history'].json.query?.uid || '').trim();
if (!uid) throw new Error('uid is required');
const paymentLabel = (value) => { const key = String(value || '').trim().toLowerCase(); if (['credit pending','pending','unpaid'].includes(key)) return '\u0e23\u0e2d\u0e0a\u0e33\u0e23\u0e30\u0e40\u0e07\u0e34\u0e19'; if (key === 'submitted') return '\u0e23\u0e2d\u0e15\u0e23\u0e27\u0e08\u0e2a\u0e2d\u0e1a\u0e01\u0e32\u0e23\u0e0a\u0e33\u0e23\u0e30\u0e40\u0e07\u0e34\u0e19'; if (['verified','paid'].includes(key)) return '\u0e0a\u0e33\u0e23\u0e30\u0e40\u0e07\u0e34\u0e19\u0e41\u0e25\u0e49\u0e27'; if (key === 'rejected') return '\u0e2b\u0e25\u0e31\u0e01\u0e10\u0e32\u0e19\u0e01\u0e32\u0e23\u0e0a\u0e33\u0e23\u0e30\u0e40\u0e07\u0e34\u0e19\u0e44\u0e21\u0e48\u0e1c\u0e48\u0e32\u0e19'; return '\u0e22\u0e31\u0e07\u0e44\u0e21\u0e48\u0e0a\u0e33\u0e23\u0e30\u0e40\u0e07\u0e34\u0e19'; };
const orders = $input.all().map(item => item.json)
  .filter(row => String(row.LINE_UID || '').trim() === uid)
  .map(row => ({
    orderId: row.Order_ID || '', timestamp: row.Timestamp || '', status: row.Status || 'Pending',
    totalAmount: Number(row.Total_Amount || 0), paymentStatus: paymentLabel(row.Payment_Status), paymentStatusRaw: row.Payment_Status || '',
    paymentSubmittedAt: row.Payment_Submitted_At || '', paymentProofUrl: row.Payment_Proof_URL || '',
    pdfUrl: String(row.PO_PDF_URL || '').split(/\n|,/).map(value => value.trim()).find(Boolean) || '',
    adjustmentReason: row.Adjustment_Reason || '', orderDetails: parseJson(row.Order_Details, {}),
  }))
  .sort((a, b) => new Date(b.timestamp || 0) - new Date(a.timestamp || 0));
return [{ json: { success: true, uid, orders } }];
